// LÖVE Shader Kit — Bloom
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float threshold;
extern float intensity;
extern float radius;

vec3 brightPart(vec4 sampleColor)
{
    float luminance = dot(sampleColor.rgb, vec3(0.2126, 0.7152, 0.0722));
    float contribution = smoothstep(threshold, 1.0, luminance);
    return sampleColor.rgb * contribution * sampleColor.a;
}

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 base = Texel(tex, textureCoords);
    vec2 offset = texelSize * radius;
    vec3 glow = vec3(0.0);

    glow += brightPart(Texel(tex, textureCoords + vec2( offset.x, 0.0))) * 0.16;
    glow += brightPart(Texel(tex, textureCoords + vec2(-offset.x, 0.0))) * 0.16;
    glow += brightPart(Texel(tex, textureCoords + vec2(0.0,  offset.y))) * 0.16;
    glow += brightPart(Texel(tex, textureCoords + vec2(0.0, -offset.y))) * 0.16;
    glow += brightPart(Texel(tex, textureCoords + vec2( offset.x,  offset.y))) * 0.09;
    glow += brightPart(Texel(tex, textureCoords + vec2(-offset.x,  offset.y))) * 0.09;
    glow += brightPart(Texel(tex, textureCoords + vec2( offset.x, -offset.y))) * 0.09;
    glow += brightPart(Texel(tex, textureCoords + vec2(-offset.x, -offset.y))) * 0.09;

    base.rgb += glow * intensity;
    return base * color;
}

// LÖVE Shader Kit — Chromatic Aberration
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float amount;
extern vec2 direction;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec2 offset = direction * texelSize * amount;
    vec4 center = Texel(tex, textureCoords);
    float red = Texel(tex, textureCoords + offset).r;
    float blue = Texel(tex, textureCoords - offset).b;
    return vec4(red, center.g, blue, center.a) * color;
}

// LÖVE Shader Kit — Color Replace
// SPDX-License-Identifier: MIT

extern vec4 sourceColor;
extern vec4 replacementColor;
extern float tolerance;
extern float softness;
extern float amount;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float colorDistance = distance(pixel.rgb, sourceColor.rgb * color.rgb);
    float matchAmount = 1.0 - smoothstep(tolerance, tolerance + max(softness, 0.0001), colorDistance);
    matchAmount *= clamp(amount, 0.0, 1.0) * replacementColor.a;
    pixel.rgb = mix(pixel.rgb, replacementColor.rgb * color.rgb, matchAmount);
    return pixel;
}

// LÖVE Shader Kit — CRT
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float curvature;
extern float scanlineStrength;
extern float rgbOffset;
extern float vignetteStrength;

vec2 curveUv(vec2 uv)
{
    vec2 centered = uv * 2.0 - 1.0;
    float distortion = dot(centered, centered) * curvature;
    centered *= 1.0 + distortion;
    return centered * 0.5 + 0.5;
}

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec2 uv = curveUv(textureCoords);
    if (uv.x < 0.0 || uv.y < 0.0 || uv.x > 1.0 || uv.y > 1.0) {
        return vec4(0.015, 0.008, 0.025, 1.0) * color;
    }

    vec2 channelOffset = vec2(texelSize.x * rgbOffset, 0.0);
    vec4 center = Texel(tex, uv);
    float red = Texel(tex, uv + channelOffset).r;
    float blue = Texel(tex, uv - channelOffset).b;
    vec4 pixel = vec4(red, center.g, blue, center.a) * color;

    float scan = 0.5 + 0.5 * sin(screenCoords.y * 3.14159265359);
    pixel.rgb *= 1.0 - scanlineStrength * (1.0 - scan);

    vec2 edge = uv * (1.0 - uv);
    float vignette = pow(clamp(edge.x * edge.y * 16.0, 0.0, 1.0), 0.22);
    pixel.rgb *= mix(1.0, vignette, clamp(vignetteStrength, 0.0, 1.0));
    return pixel;
}

// LÖVE Shader Kit — Directional Blur
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern vec2 direction;
extern float radius;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec2 safeDirection = direction;
    float directionLength = length(safeDirection);
    if (directionLength > 0.0001) {
        safeDirection /= directionLength;
    }
    vec2 stepOffset = safeDirection * texelSize * radius;

    vec4 sum = Texel(tex, textureCoords) * 0.2270270270;
    sum += Texel(tex, textureCoords + stepOffset * 0.25) * 0.1945945946;
    sum += Texel(tex, textureCoords - stepOffset * 0.25) * 0.1945945946;
    sum += Texel(tex, textureCoords + stepOffset * 0.50) * 0.1216216216;
    sum += Texel(tex, textureCoords - stepOffset * 0.50) * 0.1216216216;
    sum += Texel(tex, textureCoords + stepOffset * 0.75) * 0.0540540541;
    sum += Texel(tex, textureCoords - stepOffset * 0.75) * 0.0540540541;
    sum += Texel(tex, textureCoords + stepOffset) * 0.0162162162;
    sum += Texel(tex, textureCoords - stepOffset) * 0.0162162162;
    return sum * color;
}

// LÖVE Shader Kit — Dissolve
// SPDX-License-Identifier: MIT

extern float time;
extern float progress;
extern float noiseScale;
extern float softness;
extern float edgeWidth;
extern vec4 edgeColor;

float hash21(vec2 p)
{
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

float valueNoise(vec2 p)
{
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);

    float a = hash21(i);
    float b = hash21(i + vec2(1.0, 0.0));
    float c = hash21(i + vec2(0.0, 1.0));
    float d = hash21(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float noiseValue = valueNoise(textureCoords * noiseScale + vec2(time * 0.12, -time * 0.08));
    float threshold = mix(-softness, 1.0 + softness, clamp(progress, 0.0, 1.0));
    float visible = smoothstep(threshold - softness, threshold + softness, noiseValue);
    float edge = 1.0 - smoothstep(0.0, max(edgeWidth, 0.0001), abs(noiseValue - threshold));
    edge *= step(threshold, noiseValue) * edgeColor.a;

    pixel.rgb = mix(pixel.rgb, edgeColor.rgb * color.rgb, edge);
    pixel.a *= visible;
    return pixel;
}

// LÖVE Shader Kit — Film Grain
// SPDX-License-Identifier: MIT

extern float time;
extern float amount;
extern float fps;

float hash21(vec2 p)
{
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float frame = floor(time * max(fps, 1.0));
    float noiseValue = hash21(screenCoords + vec2(frame * 17.0, frame * 31.0)) - 0.5;
    pixel.rgb = clamp(pixel.rgb + noiseValue * amount, 0.0, 1.0);
    return pixel;
}

// LÖVE Shader Kit — Glitch
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float time;
extern float amount;
extern float blockCount;
extern float speed;
extern float rgbOffset;

float hash21(vec2 p)
{
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    float frame = floor(time * max(speed, 0.001));
    float band = floor(textureCoords.y * max(blockCount, 1.0));
    float randomValue = hash21(vec2(band, frame));
    float glitchBandMask = step(1.0 - clamp(amount, 0.0, 1.0), randomValue);
    float shift = (hash21(vec2(band + 17.0, frame + 9.0)) - 0.5) * 0.16 * amount * glitchBandMask;
    vec2 shiftedUv = clamp(textureCoords + vec2(shift, 0.0), vec2(0.0), vec2(1.0));
    vec2 channelOffset = vec2(texelSize.x * rgbOffset * (0.35 + glitchBandMask), 0.0);

    float red = Texel(tex, clamp(shiftedUv + channelOffset, vec2(0.0), vec2(1.0))).r;
    vec4 center = Texel(tex, shiftedUv);
    float blue = Texel(tex, clamp(shiftedUv - channelOffset, vec2(0.0), vec2(1.0))).b;
    return vec4(red, center.g, blue, center.a) * color;
}

// LÖVE Shader Kit — Grayscale
// SPDX-License-Identifier: MIT

extern float amount;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float luminance = dot(pixel.rgb, vec3(0.2126, 0.7152, 0.0722));
    pixel.rgb = mix(pixel.rgb, vec3(luminance), clamp(amount, 0.0, 1.0));
    return pixel;
}

// LÖVE Shader Kit — Hit Flash
// SPDX-License-Identifier: MIT

extern vec4 flashColor;
extern float amount;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float blendAmount = clamp(amount, 0.0, 1.0) * flashColor.a;
    pixel.rgb = mix(pixel.rgb, flashColor.rgb * color.rgb, blendAmount);
    return pixel;
}

// LÖVE Shader Kit — Outline
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern vec4 outlineColor;
extern float thickness;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 base = Texel(tex, textureCoords) * color;
    if (base.a > 0.001) {
        return base;
    }

    vec2 offset = texelSize * max(thickness, 0.0);
    float alpha = 0.0;
    alpha = max(alpha, Texel(tex, textureCoords + vec2( offset.x, 0.0)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2(-offset.x, 0.0)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2(0.0,  offset.y)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2(0.0, -offset.y)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2( offset.x,  offset.y)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2(-offset.x,  offset.y)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2( offset.x, -offset.y)).a);
    alpha = max(alpha, Texel(tex, textureCoords + vec2(-offset.x, -offset.y)).a);

    return vec4(outlineColor.rgb * color.rgb, alpha * outlineColor.a * color.a);
}

// LÖVE Shader Kit — Pixelate
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float pixelSize;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec2 cell = texelSize * max(pixelSize, 1.0);
    vec2 uv = (floor(textureCoords / cell) + 0.5) * cell;
    return Texel(tex, uv) * color;
}

// LÖVE Shader Kit — Posterize
// SPDX-License-Identifier: MIT

extern float levels;
extern float amount;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float safeLevels = max(floor(levels + 0.5), 2.0);
    vec3 quantized = floor(pixel.rgb * (safeLevels - 1.0) + 0.5) / (safeLevels - 1.0);
    pixel.rgb = mix(pixel.rgb, quantized, clamp(amount, 0.0, 1.0));
    return pixel;
}

// LÖVE Shader Kit — Radial Wipe
// SPDX-License-Identifier: MIT

extern float progress;
extern float softness;
extern float edgeWidth;
extern vec2 center;
extern vec4 edgeColor;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float maxDistance = max(max(length(center), length(vec2(1.0, 0.0) - center)),
                            max(length(vec2(0.0, 1.0) - center), length(vec2(1.0) - center)));
    float radialDistance = length(textureCoords - center) / max(maxDistance, 0.0001);
    float boundary = clamp(progress, 0.0, 1.0);
    float visible = 1.0 - smoothstep(boundary, boundary + max(softness, 0.0001), radialDistance);
    float edge = 1.0 - smoothstep(edgeWidth, edgeWidth + max(softness, 0.0001), abs(radialDistance - boundary));
    edge *= visible * edgeColor.a;

    pixel.rgb = mix(pixel.rgb, edgeColor.rgb, edge);
    pixel.a *= visible;
    return pixel;
}

// LÖVE Shader Kit — Scanlines
// SPDX-License-Identifier: MIT

extern float time;
extern float spacing;
extern float strength;
extern float speed;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float phase = (screenCoords.y + time * speed * spacing) * 6.28318530718 / max(spacing, 0.001);
    float scan = 0.5 + 0.5 * sin(phase);
    pixel.rgb *= 1.0 - clamp(strength, 0.0, 1.0) * (1.0 - scan);
    return pixel;
}

// LÖVE Shader Kit — Silhouette
// SPDX-License-Identifier: MIT

extern vec4 silhouetteColor;
extern float amount;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    float blendAmount = clamp(amount, 0.0, 1.0) * silhouetteColor.a;
    pixel.rgb = mix(pixel.rgb, silhouetteColor.rgb * color.rgb, blendAmount);
    return pixel;
}

// LÖVE Shader Kit — Vignette
// SPDX-License-Identifier: MIT

extern float aspect;
extern float radius;
extern float softness;
extern float intensity;
extern vec4 vignetteColor;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec4 pixel = Texel(tex, textureCoords) * color;
    vec2 centered = textureCoords - vec2(0.5);
    centered.x *= aspect;
    float distanceFromCenter = length(centered);
    float mask = smoothstep(radius, radius + max(softness, 0.0001), distanceFromCenter);
    float blendAmount = mask * clamp(intensity, 0.0, 1.0) * vignetteColor.a;
    pixel.rgb = mix(pixel.rgb, vignetteColor.rgb, blendAmount);
    return pixel;
}

// LÖVE Shader Kit — Wave
// SPDX-License-Identifier: MIT

extern vec2 texelSize;
extern float time;
extern float amplitude;
extern float frequency;
extern float speed;

vec4 effect(vec4 color, Image tex, vec2 textureCoords, vec2 screenCoords)
{
    vec2 displacement;
    displacement.x = sin(textureCoords.y * frequency + time * speed);
    displacement.y = cos(textureCoords.x * frequency * 0.73 + time * speed * 0.81);
    vec2 uv = textureCoords + displacement * texelSize * amplitude;

    if (uv.x < 0.0 || uv.y < 0.0 || uv.x > 1.0 || uv.y > 1.0) {
        return vec4(0.0);
    }
    return Texel(tex, uv) * color;
}
